import { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import PollComponent from './PollComponent';

const C = { amber: '#D4883A', border: '#E8E0D0', text: '#2C2416', muted: '#A0907A' };

export default function ChatBox({ messages, currentUser, socket, groupId }) {
    const [text, setText] = useState('');
    const [showPicker, setShowPicker] = useState(false);
    const [showPollBuilder, setShowPollBuilder] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState([]);
    const [selectedRestaurants, setSelectedRestaurants] = useState([]);
    const bottomRef = useRef(null);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    // ── Send plain text ────────────────────────────────────────────────────────
    const sendText = () => {
        if (!text.trim() || !socket) return;
        socket.emit('sendMessage', { groupId, text, type: 'text' });
        setText('');
    };

    // ── Search restaurants ─────────────────────────────────────────────────────
    const searchRestaurants = async () => {
        if (!searchQuery.trim()) return;
        try {
            const res = await axios.get(`/restaurants?search=${encodeURIComponent(searchQuery)}&limit=6`);
            // Handle both { data: [...] } and { data: { restaurants: [...] } } shapes
            const list = Array.isArray(res.data.data)
                ? res.data.data
                : res.data.data?.restaurants || [];
            setSearchResults(list);
        } catch {
            setSearchResults([]);
        }
    };

    // ── Share selected restaurants as individual messages ──────────────────────
    const shareRestaurants = () => {
        if (!socket || selectedRestaurants.length === 0) return;
        selectedRestaurants.forEach(r => {
            socket.emit('sendMessage', {
                groupId,
                type: 'restaurant_share',
                restaurantData: {
                    restaurantId: r._id,
                    name: r.name,
                    image: r.images?.[0] || r.image || '',
                    rating: r.averageRating || r.rating || 0,
                    cuisine: r.cuisine || r.cuisineType || '',
                },
            });
        });
        resetPicker();
    };

    const launchPoll = () => {
        if (!socket || selectedRestaurants.length < 2) return;
        socket.emit('createPoll', {
            groupId,
            question: 'Where should we go?',
            restaurantOptions: selectedRestaurants.map(r => ({
                restaurantId: r._id,
                name: r.name,
                image: r.images?.[0] || r.image || '',
                rating: r.averageRating || r.rating || 0,
                cuisine: r.cuisine || r.cuisineType || '',
            })),
        });
        resetPicker();
    };

    const resetPicker = () => {
        setSelectedRestaurants([]);
        setShowPicker(false);
        setShowPollBuilder(false);
        setSearchResults([]);
        setSearchQuery('');
    };

    const toggleSelect = (r) => {
        setSelectedRestaurants(prev =>
            prev.find(x => x._id === r._id)
                ? prev.filter(x => x._id !== r._id)
                : [...prev, r]
        );
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', background: '#F7F4F0' }}>

            {/* ── Message list ──────────────────────────────────────────────────── */}
            <div style={{ flex: 1, overflowY: 'auto', padding: '16px 16px 8px' }}>
                {messages.length === 0 && (
                    <p style={{ textAlign: 'center', color: C.muted, fontSize: 13, marginTop: 40 }}>
                        No messages yet. Say hi!
                    </p>
                )}

                {messages.map(msg => {
                    const isMe = (msg.sender?._id || msg.sender) === currentUser?._id;

                    // ── Poll message ────────────────────────────────────────────────
                    if (msg.type === 'poll') {
                        return (
                            <div key={msg._id} style={{ display: 'flex', justifyContent: 'center', margin: '12px 0' }}>
                                <PollComponent
                                    poll={msg.pollId}
                                    socket={socket}
                                    currentUser={currentUser}
                                />
                            </div>
                        );
                    }

                    // ── Restaurant share ────────────────────────────────────────────
                    if (msg.type === 'restaurant_share') {
                        const r = msg.restaurantData;
                        return (
                            <div key={msg._id}
                                style={{ display: 'flex', justifyContent: isMe ? 'flex-end' : 'flex-start', marginBottom: 10 }}>
                                <div style={{
                                    background: '#fff', borderRadius: 14, border: `1px solid ${C.border}`,
                                    overflow: 'hidden', maxWidth: 240, boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
                                }}>
                                    {r?.image && (
                                        <img src={r.image} alt={r.name}
                                            style={{ width: '100%', height: 120, objectFit: 'cover' }} />
                                    )}
                                    <div style={{ padding: '10px 12px' }}>
                                        <div style={{ fontWeight: 700, fontSize: 14, color: C.text }}>{r?.name}</div>
                                        <div style={{ fontSize: 12, color: C.muted, marginTop: 2 }}>
                                            {r?.cuisine} · ⭐ {Number(r?.rating || 0).toFixed(1)}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    }

                    // ── Text message ────────────────────────────────────────────────
                    return (
                        <div key={msg._id}
                            style={{
                                display: 'flex', flexDirection: 'column',
                                alignItems: isMe ? 'flex-end' : 'flex-start',
                                marginBottom: 8,
                            }}>
                            {!isMe && (
                                <span style={{ fontSize: 11, color: C.muted, marginBottom: 3, marginLeft: 4 }}>
                                    {msg.sender?.name}
                                </span>
                            )}
                            <div style={{
                                maxWidth: '70%', padding: '9px 14px', fontSize: 14,
                                borderRadius: isMe ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
                                background: isMe ? C.amber : '#fff',
                                color: isMe ? '#fff' : C.text,
                                boxShadow: '0 1px 4px rgba(0,0,0,0.06)',
                            }}>
                                {msg.text}
                            </div>
                        </div>
                    );
                })}
                <div ref={bottomRef} />
            </div>

            {/* ── Restaurant picker panel ────────────────────────────────────────── */}
            {showPicker && (
                <div style={{ borderTop: `1px solid ${C.border}`, background: '#fff', padding: 12 }}>
                    <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
                        <input
                            type="text"
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && searchRestaurants()}
                            placeholder="Search restaurants..."
                            style={{
                                flex: 1, border: `1.5px solid ${C.border}`, borderRadius: 8,
                                padding: '8px 12px', fontSize: 13, outline: 'none'
                            }}
                        />
                        <button onClick={searchRestaurants}
                            style={{
                                background: C.amber, color: '#fff', border: 'none', borderRadius: 8,
                                padding: '8px 14px', fontSize: 13, cursor: 'pointer'
                            }}>
                            Search
                        </button>
                    </div>

                    <div style={{ maxHeight: 160, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 4 }}>
                        {searchResults.map(r => {
                            const selected = selectedRestaurants.find(x => x._id === r._id);
                            return (
                                <div key={r._id} onClick={() => toggleSelect(r)} style={{
                                    display: 'flex', alignItems: 'center', gap: 8, padding: '8px 10px',
                                    borderRadius: 8, cursor: 'pointer',
                                    background: selected ? '#FFF7ED' : 'transparent',
                                    border: `1px solid ${selected ? C.amber + '60' : 'transparent'}`,
                                    transition: 'all 0.15s',
                                }}>
                                    {(r.images?.[0] || r.image) && (
                                        <img src={r.images?.[0] || r.image} alt={r.name}
                                            style={{ width: 32, height: 32, borderRadius: 6, objectFit: 'cover' }} />
                                    )}
                                    <span style={{ fontSize: 13, fontWeight: 600, color: C.text }}>{r.name}</span>
                                    <span style={{ fontSize: 11, color: C.muted, marginLeft: 'auto' }}>{r.cuisine}</span>
                                </div>
                            );
                        })}
                    </div>

                    {selectedRestaurants.length > 0 && (
                        <div style={{ display: 'flex', gap: 8, marginTop: 10 }}>
                            <button onClick={shareRestaurants} style={{
                                background: C.amber, color: '#fff', border: 'none', borderRadius: 8,
                                padding: '8px 14px', fontSize: 13, cursor: 'pointer',
                            }}>
                                Share ({selectedRestaurants.length})
                            </button>
                            {selectedRestaurants.length >= 2 && (
                                <button onClick={() => { setShowPollBuilder(true); setShowPicker(false); }}
                                    style={{
                                        background: 'transparent', color: C.amber, border: `1px solid ${C.amber}`,
                                        borderRadius: 8, padding: '8px 14px', fontSize: 13, cursor: 'pointer',
                                    }}>
                                    Create Poll
                                </button>
                            )}
                        </div>
                    )}
                </div>
            )}

            {/* ── Poll builder confirm panel ─────────────────────────────────────── */}
            {showPollBuilder && (
                <div style={{ borderTop: `1px solid ${C.border}`, background: '#fff', padding: 12 }}>
                    <p style={{ fontSize: 13, fontWeight: 600, color: C.text, marginBottom: 8 }}>
                        Launch a poll with these {selectedRestaurants.length} options?
                    </p>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 10 }}>
                        {selectedRestaurants.map(r => (
                            <span key={r._id} style={{
                                fontSize: 12, background: '#FFF7ED', color: C.amber,
                                border: `1px solid ${C.amber}40`, borderRadius: 20, padding: '3px 10px',
                            }}>{r.name}</span>
                        ))}
                    </div>
                    <div style={{ display: 'flex', gap: 8 }}>
                        <button onClick={launchPoll} style={{
                            background: C.amber, color: '#fff', border: 'none', borderRadius: 8,
                            padding: '8px 16px', fontSize: 13, cursor: 'pointer',
                        }}>
                            Launch Poll
                        </button>
                        <button onClick={resetPicker}
                            style={{ background: 'none', border: 'none', color: C.muted, fontSize: 13, cursor: 'pointer' }}>
                            Cancel
                        </button>
                    </div>
                </div>
            )}

            {/* ── Input bar ─────────────────────────────────────────────────────── */}
            <div style={{
                display: 'flex', alignItems: 'center', gap: 8, padding: '12px 16px',
                borderTop: `1px solid ${C.border}`, background: '#fff',
            }}>
                <button
                    onClick={() => { setShowPicker(v => !v); setShowPollBuilder(false); }}
                    title="Share a restaurant"
                    style={{
                        background: 'none', border: 'none', fontSize: 22, cursor: 'pointer',
                        color: showPicker ? C.amber : C.muted, padding: 0, lineHeight: 1
                    }}>
                    🍽
                </button>
                <input
                    type="text"
                    value={text}
                    onChange={e => setText(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && sendText()}
                    placeholder="Type a message..."
                    style={{
                        flex: 1, border: `1.5px solid ${C.border}`, borderRadius: 24,
                        padding: '9px 16px', fontSize: 14, outline: 'none',
                        background: '#FDFAF6', color: C.text, fontFamily: "'DM Sans',sans-serif",
                    }}
                />
                <button onClick={sendText} disabled={!text.trim()} style={{
                    background: text.trim() ? C.amber : '#E8E0D0',
                    color: '#fff', border: 'none', borderRadius: 24,
                    padding: '9px 18px', fontSize: 14, fontWeight: 600,
                    cursor: text.trim() ? 'pointer' : 'not-allowed',
                    transition: 'background 0.2s',
                }}>
                    Send
                </button>
            </div>
        </div>
    );
}
